### Checking for Prime Numbers in an Array

Here's a JavaScript function that checks if any of the numbers in the input array are prime numbers.

```javascript
/**
 * Checks if a number is prime.
 * @param {number} num - The number to check.
 * @returns {boolean} True if the number is prime, false otherwise.
 */
function isPrime(num) {
    if (num <= 1) return false;
    for (let i = 2, sqrt = Math.sqrt(num); i <= sqrt; i++) {
        if (num % i === 0) return false;
    }
    return true;
}

/**
 * Checks if any number in the array is prime.
 * @param {number[]} arr - The array of numbers to check.
 */
function checkPrimeNumbers(arr) {
    if (!Array.isArray(arr) || arr.length!== 5) {
        throw new Error('Input must be an array of 5 numbers');
    }

    arr.forEach(num => {
        if (typeof num!== 'number' || isNaN(num)) {
            throw new Error('Array must only contain numbers');
        }
    });

    arr.forEach(num => {
        if (isPrime(num)) {
            console.log(`The number ${num} is a prime number.`);
        }
    });
}

// Example usage:
const numbers = [2, 4, 6, 8, 10];
checkPrimeNumbers(numbers);
```

